import java.io.File;
import java.util.Scanner;

public class SecurePathTraversal {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a file path within a specific directory: ");
        String basePath = "/path/to/your/directory/";

        String filePath = scanner.next();

        if (filePath.contains("..")) {
            System.out.println("Invalid file path.");
            return;
        }

        File file = new File(basePath + filePath);

        if (file.exists() && file.getAbsolutePath().startsWith(basePath)) {
            System.out.println("File exists within the specified directory.");
            // Do something with the file
        } else {
            System.out.println("File does not exist or is outside the specified directory.");
        }
    }
}

